import { Component, OnInit } from '@angular/core';
import { AuthService } from '../../core/services/auth.service';

@Component({
  selector: 'app-main-layout',
  templateUrl: './main-layout.component.html'
})
export class MainLayoutComponent implements OnInit {
  constructor(private readonly authService: AuthService) {
  }

  ngOnInit(): void {
    this.authService.hydrateUser();
  }
}
<div class="min-h-screen px-4 py-4 md:px-6">
  <div class="mx-auto grid min-h-[calc(100vh-2rem)] max-w-7xl gap-4 lg:grid-cols-[280px_1fr]">
    <app-sidebar></app-sidebar>

    <main class="space-y-4">
      <app-navbar></app-navbar>
      <section class="glass-panel min-h-[calc(100vh-9rem)] p-4 md:p-6">
        <router-outlet></router-outlet>
      </section>
    </main>
  </div>
</div>
